class Solution {
public:
    int countWinningSequences(string s) {
        const long long MOD = 1'000'000'007;
        int n = s.size();
        // dp[i][last][diff] = count
        // diff = BobScore - AliceScore, shifted by n to keep non-negative
        // diff range: [-n, n] -> [0, 2n]
        vector<vector<vector<long long>>> dp(n + 1, vector<vector<long long>>(3, vector<long long>(2 * n + 1, 0)));

        // Base: 0 rounds, no last move, diff = 0
        // We'll handle first round separately
        for (int b = 0; b < 3; ++b) {
            int diff = 0;
            char bob = "FWE"[b];
            char alice = s[0];
            int delta = 0;
            if (bob == 'F' && alice == 'E') delta = 1;
            else if (bob == 'W' && alice == 'F') delta = 1;
            else if (bob == 'E' && alice == 'W') delta = 1;
            else if (alice == 'F' && bob == 'E') delta = -1;
            else if (alice == 'W' && bob == 'F') delta = -1;
            else if (alice == 'E' && bob == 'W') delta = -1;
            dp[1][b][n + delta] = 1;
        }

        for (int i = 1; i < n; ++i) {
            for (int last = 0; last < 3; ++last) {
                for (int d = 0; d <= 2 * n; ++d) {
                    if (dp[i][last][d] == 0) continue;
                    for (int b = 0; b < 3; ++b) {
                        if (b == last) continue;
                        char bob = "FWE"[b];
                        char alice = s[i];
                        int delta = 0;
                        if (bob == 'F' && alice == 'E') delta = 1;
                        else if (bob == 'W' && alice == 'F') delta = 1;
                        else if (bob == 'E' && alice == 'W') delta = 1;
                        else if (alice == 'F' && bob == 'E') delta = -1;
                        else if (alice == 'W' && bob == 'F') delta = -1;
                        else if (alice == 'E' && bob == 'W') delta = -1;
                        int new_d = d + delta;
                        if (new_d >= 0 && new_d <= 2 * n) {
                            dp[i + 1][b][new_d] = (dp[i + 1][b][new_d] + dp[i][last][d]) % MOD;
                        }
                    }
                }
            }
        }

        long long res = 0;
        for (int b = 0; b < 3; ++b) {
            for (int d = n + 1; d <= 2 * n; ++d) {
                res = (res + dp[n][b][d]) % MOD;
            }
        }
        return (int)res;
    }
};
